type $_FromRdfResourceFunction<T> = (
  resource: Resource,
  options: {
    context: undefined | unknown;
    graph: Exclude<Quad_Graph, Variable> | undefined;
    ignoreRdfType: boolean;
    objectSet: $ObjectSet;
    preferredLanguages: readonly string[] | undefined;
  },
) => Either<Error, T>;

export type $_ToRdfResourceFunction<
  IdentifierT extends Resource.Identifier,
  ObjectT extends { $identifier: () => IdentifierT },
> = (parameters: {
  graph: Exclude<Quad_Graph, Variable> | undefined;
  ignoreRdfType: boolean;
  object: ObjectT;
  resource: Resource<IdentifierT>;
  resourceSet: ResourceSet;
}) => void;

/**
 * Compare two arrays element-wise with the provided elementEquals function.
 */
function $arrayEquals<T>(
  leftArray: readonly T[],
  rightArray: readonly T[],
  elementEquals: (left: T, right: T) => boolean | $EqualsResult,
): $EqualsResult {
  if (leftArray.length !== rightArray.length) {
    return Left({ left: leftArray, right: rightArray, type: "array-length" });
  }

  for (
    let leftElementIndex = 0;
    leftElementIndex < leftArray.length;
    leftElementIndex++
  ) {
    const leftElement = leftArray[leftElementIndex];

    const rightUnequals: $EqualsResult.Unequal[] = [];
    for (
      let rightElementIndex = 0;
      rightElementIndex < rightArray.length;
      rightElementIndex++
    ) {
      const rightElement = rightArray[rightElementIndex];

      const leftElementEqualsRightElement =
        $EqualsResult.fromBooleanEqualsResult(
          leftElement,
          rightElement,
          elementEquals(leftElement, rightElement),
        );
      if (leftElementEqualsRightElement.isRight()) {
        break; // left element === right element, break out of the right iteration
      }
      rightUnequals.push(
        leftElementEqualsRightElement.extract() as $EqualsResult.Unequal,
      );
    }

    if (rightUnequals.length === rightArray.length) {
      // All right elements were unequal to the left element
      return Left({
        left: {
          array: leftArray,
          element: leftElement,
          elementIndex: leftElementIndex,
        },
        right: { array: rightArray, unequals: rightUnequals },
        type: "array-element",
      });
    }
    // Else there was a right element equal to the left element, continue to the next left element
  }

  return $EqualsResult.Equal;
}

function $arrayIntersection<T>(
  left: readonly T[],
  right: readonly T[],
): readonly T[] {
  if (left.length === 0) {
    return right;
  }
  if (right.length === 0) {
    return left;
  }

  const intersection = new Set<T>();
  if (left.length <= right.length) {
    const rightSet = new Set(right);
    for (const leftElement of left) {
      if (rightSet.has(leftElement)) {
        intersection.add(leftElement);
      }
    }
  } else {
    const leftSet = new Set(left);
    for (const rightElement of right) {
      if (leftSet.has(rightElement)) {
        intersection.add(rightElement);
      }
    }
  }
  return [...intersection];
}

/**
 * Create a Literal from a BigDecimal.
 */
function $bigDecimalLiteral(value: BigDecimal): Literal {
  return dataFactory.literal(value.toFixed(), $RdfVocabularies.xsd.decimal);
}

const $bigDecimalSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $NumericFilter<BigDecimal>,
  $NumericSchema<BigDecimal>
> = ({ filter, propertyPatterns, schema, valueVariable }) => {
  const filterPatterns: $SparqlFilterPattern[] = [];

  if (filter) {
    if (filter.in !== undefined && filter.in.length > 0) {
      filterPatterns.push({
        expression: {
          args: [valueVariable, filter.in.map($bigDecimalLiteral)],
          operator: "in",
          type: "operation",
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.maxExclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "<",
          args: [valueVariable, $bigDecimalLiteral(filter.maxExclusive)],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.maxInclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "<=",
          args: [valueVariable, $bigDecimalLiteral(filter.maxInclusive)],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.minExclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: ">",
          args: [valueVariable, $bigDecimalLiteral(filter.minExclusive)],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.minInclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: ">=",
          args: [valueVariable, $bigDecimalLiteral(filter.minInclusive)],
        },
        lift: true,
        type: "filter",
      });
    }
  }

  const schemaPatterns: $SparqlPattern[] = [];
  if (schema.in && schema.in.length > 0) {
    schemaPatterns.push({
      expression: {
        args: [valueVariable, schema.in.map($bigDecimalLiteral)],
        operator: "in",
        type: "operation",
      },
      lift: true,
      type: "filter",
    });
  }

  return (propertyPatterns as readonly $SparqlPattern[])
    .concat(schemaPatterns)
    .concat(filterPatterns);
};

interface $BlankNodeFilter {}

interface $BlankNodeSchema {
  readonly kind: "BlankNode";
}

const $blankNodeSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $BlankNodeFilter,
  $BlankNodeSchema
> = ({ propertyPatterns }) => propertyPatterns;

/**
 * Compare two objects with equals(other: T): boolean methods and return an $EqualsResult.
 */
function $booleanEquals<T extends { equals: (other: T) => boolean }>(
  left: T,
  right: T,
): $EqualsResult {
  return $EqualsResult.fromBooleanEqualsResult(left, right, left.equals(right));
}

interface $BooleanFilter {
  readonly value?: boolean;
}

interface $BooleanSchema {
  readonly kind: "Boolean";
  readonly in?: readonly boolean[];
}

const $booleanSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $BooleanFilter,
  $BooleanSchema
> = ({ filter, valueVariable, ...otherParameters }) => {
  const filterPatterns: $SparqlFilterPattern[] = [];

  if (filter) {
    if (filter.value !== undefined) {
      filterPatterns.push(
        $sparqlValueInPattern({
          lift: true,
          valueVariable,
          valueIn: [filter.value],
        }),
      );
    }
  }

  return $termSchemaSparqlPatterns({
    ...otherParameters,
    filterPatterns,
    valueVariable,
  });
};

type $CollectionFilter<ItemFilterT> = ItemFilterT & {
  readonly $maxCount?: number;
  readonly $minCount?: number;
};

interface $CollectionSchema<ItemSchemaT> {
  readonly item: () => ItemSchemaT;
  readonly kind: "List" | "Set";
  readonly minCount?: number;
}

/**
 * Remove undefined values from a record.
 */
function $compactRecord<KeyT extends string, ValueT extends {}>(
  record: Record<KeyT, ValueT | undefined>,
): Record<KeyT, ValueT> {
  return globalThis.Object.entries(record).reduce(
    (definedProperties, [propertyName, propertyValue]) => {
      if (propertyValue !== undefined) {
        definedProperties[propertyName as KeyT] = propertyValue as ValueT;
      }
      return definedProperties;
    },
    {} as Record<KeyT, ValueT>,
  );
}

/**
 * Compare two Dates and return an $EqualsResult.
 */
function $dateEquals(left: Date, right: Date): $EqualsResult {
  return $EqualsResult.fromBooleanEqualsResult(
    left,
    right,
    left.getTime() === right.getTime(),
  );
}

interface $DateFilter {
  readonly in?: readonly Date[];
  readonly maxExclusive?: Date;
  readonly maxInclusive?: Date;
  readonly minExclusive?: Date;
  readonly minInclusive?: Date;
}

interface $DateSchema {
  in?: readonly Date[];
  kind: "Date" | "DateTime";
}

const $dateSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $DateFilter,
  $DateSchema
> = ({ filter, schema, valueVariable, ...otherParameters }) => {
  const filterPatterns: $SparqlFilterPattern[] = [];

  if (filter) {
    if (filter.in !== undefined && filter.in.length > 0) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "in",
          args: [
            valueVariable,
            filter.in.map((inValue) =>
              $literalFactory.date(
                inValue,
                schema.kind === "Date"
                  ? $RdfVocabularies.xsd.date
                  : $RdfVocabularies.xsd.dateTime,
              ),
            ),
          ],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.maxExclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "<",
          args: [
            valueVariable,
            $literalFactory.date(
              filter.maxExclusive,
              schema.kind === "Date"
                ? $RdfVocabularies.xsd.date
                : $RdfVocabularies.xsd.dateTime,
            ),
          ],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.maxInclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "<=",
          args: [
            valueVariable,
            $literalFactory.date(
              filter.maxInclusive,
              schema.kind === "Date"
                ? $RdfVocabularies.xsd.date
                : $RdfVocabularies.xsd.dateTime,
            ),
          ],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.minExclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: ">",
          args: [
            valueVariable,
            $literalFactory.date(
              filter.minExclusive,
              schema.kind === "Date"
                ? $RdfVocabularies.xsd.date
                : $RdfVocabularies.xsd.dateTime,
            ),
          ],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.minInclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: ">=",
          args: [
            valueVariable,
            $literalFactory.date(
              filter.minInclusive,
              schema.kind === "Date"
                ? $RdfVocabularies.xsd.date
                : $RdfVocabularies.xsd.dateTime,
            ),
          ],
        },
        lift: true,
        type: "filter",
      });
    }
  }

  return $termSchemaSparqlPatterns({
    ...otherParameters,
    filterPatterns,
    schema,
    valueVariable,
  });
};

/**
 * Decidoe a BigDecimal from a Literal.
 */
function $decodeBigDecimalLiteral(literal: Literal): Either<Error, BigDecimal> {
  return Either.encase(() => new BigDecimal(literal.value));
}

function $deduplicateSparqlPatterns(
  patterns: readonly $SparqlPattern[],
): readonly $SparqlPattern[] {
  if (patterns.length === 0) {
    return patterns;
  }

  const deduplicatedPatterns: $SparqlPattern[] = [];
  const deduplicatePatternStrings = new Set<string>();
  for (const pattern of patterns) {
    const patternString = JSON.stringify(pattern);
    if (!deduplicatePatternStrings.has(patternString)) {
      deduplicatePatternStrings.add(patternString);
      deduplicatedPatterns.push(pattern);
    }
  }
  return deduplicatedPatterns;
}

interface $DefaultValueSchema<ItemSchemaT> {
  readonly defaultValue: Literal | NamedNode;
  readonly item: () => ItemSchemaT;
  readonly kind: "DefaultValue";
}

function $defaultValueSparqlWherePatterns<ItemFilterT, ItemSchemaT>(
  itemSparqlWherePatternsFunction: $ValueSparqlWherePatternsFunction<
    ItemFilterT,
    ItemSchemaT
  >,
): $ValueSparqlWherePatternsFunction<
  ItemFilterT,
  $DefaultValueSchema<ItemSchemaT>
> {
  return ({ schema, ...otherParameters }) => {
    const [itemSparqlWherePatterns, liftSparqlPatterns] = $liftSparqlPatterns(
      itemSparqlWherePatternsFunction({
        ...otherParameters,
        schema: schema.item(),
      }),
    );
    return [
      { patterns: itemSparqlWherePatterns.concat(), type: "optional" },
      ...liftSparqlPatterns,
    ];
  };
}

export type $EqualsResult = Either<$EqualsResult.Unequal, true>;

export namespace $EqualsResult {
  export const Equal: $EqualsResult = Right(true);

  export function fromBooleanEqualsResult(
    left: any,
    right: any,
    equalsResult: boolean | $EqualsResult,
  ): $EqualsResult {
    if (typeof equalsResult !== "boolean") {
      return equalsResult;
    }

    if (equalsResult) {
      return Equal;
    }

    return Left({ left, right, type: "boolean" });
  }

  export type Unequal =
    | {
        readonly left: {
          readonly array: readonly any[];
          readonly element: any;
          readonly elementIndex: number;
        };
        readonly right: {
          readonly array: readonly any[];
          readonly unequals: readonly Unequal[];
        };
        readonly type: "array-element";
      }
    | {
        readonly left: readonly any[];
        readonly right: readonly any[];
        readonly type: "array-length";
      }
    | { readonly left: any; readonly right: any; readonly type: "boolean" }
    | { readonly right: any; readonly type: "left-null" }
    | {
        readonly left: any;
        readonly right: any;
        readonly propertyName: string;
        readonly propertyValuesUnequal: Unequal;
        readonly type: "property";
      }
    | { readonly left: any; readonly type: "right-null" };
}

function $filterArray<ItemT, ItemFilterT>(
  filterItem: (itemFilter: ItemFilterT, item: ItemT) => boolean,
) {
  return (
    filter: $CollectionFilter<ItemFilterT>,
    values: readonly ItemT[],
  ): boolean => {
    for (const value of values) {
      if (!filterItem(filter, value)) {
        return false;
      }
    }

    if (filter.$maxCount !== undefined && values.length > filter.$maxCount) {
      return false;
    }

    if (filter.$minCount !== undefined && values.length < filter.$minCount) {
      return false;
    }

    return true;
  };
}

function $filterBigDecimal(
  filter: $NumericFilter<BigDecimal>,
  value: BigDecimal,
) {
  if (
    filter.in !== undefined &&
    !filter.in.some((inValue) => inValue.equals(value))
  ) {
    return false;
  }

  if (
    filter.maxExclusive !== undefined &&
    value.greaterThanOrEqualTo(filter.maxExclusive)
  ) {
    return false;
  }

  if (
    filter.maxInclusive !== undefined &&
    value.greaterThan(filter.maxInclusive)
  ) {
    return false;
  }

  if (
    filter.minExclusive !== undefined &&
    value.lessThanOrEqualTo(filter.minExclusive)
  ) {
    return false;
  }

  if (
    filter.minInclusive !== undefined &&
    value.lessThan(filter.minInclusive)
  ) {
    return false;
  }

  return true;
}

function $filterBlankNode(_filter: $BlankNodeFilter, _value: BlankNode) {
  return true;
}

function $filterBoolean(filter: $BooleanFilter, value: boolean) {
  if (filter.value !== undefined && value !== filter.value) {
    return false;
  }

  return true;
}

function $filterDate(filter: $DateFilter, value: Date) {
  if (
    filter.in !== undefined &&
    !filter.in.some((inValue) => inValue.getTime() === value.getTime())
  ) {
    return false;
  }

  if (
    filter.maxExclusive !== undefined &&
    value.getTime() >= filter.maxExclusive.getTime()
  ) {
    return false;
  }

  if (
    filter.maxInclusive !== undefined &&
    value.getTime() > filter.maxInclusive.getTime()
  ) {
    return false;
  }

  if (
    filter.minExclusive !== undefined &&
    value.getTime() <= filter.minExclusive.getTime()
  ) {
    return false;
  }

  if (
    filter.minInclusive !== undefined &&
    value.getTime() < filter.minInclusive.getTime()
  ) {
    return false;
  }

  return true;
}

function $filterIdentifier(
  filter: $IdentifierFilter,
  value: BlankNode | NamedNode,
) {
  if (
    filter.in !== undefined &&
    !filter.in.some((inValue) => inValue.equals(value))
  ) {
    return false;
  }

  if (filter.type !== undefined && value.termType !== filter.type) {
    return false;
  }

  return true;
}

function $filterIri(filter: $IriFilter, value: NamedNode) {
  if (
    filter.in !== undefined &&
    !filter.in.some((inValue) => inValue.equals(value))
  ) {
    return false;
  }

  return true;
}

function $filterLiteral(filter: $LiteralFilter, value: Literal): boolean {
  return $filterTerm(filter, value);
}

function $filterMaybe<ItemT, ItemFilterT>(
  filterItem: (itemFilter: ItemFilterT, item: ItemT) => boolean,
) {
  return (filter: $MaybeFilter<ItemFilterT>, value: Maybe<ItemT>): boolean => {
    if (filter !== null) {
      if (value.isNothing()) {
        return false;
      }

      if (!filterItem(filter, value.extract()!)) {
        return false;
      }
    } else {
      if (value.isJust()) {
        return false;
      }
    }

    return true;
  };
}

function $filterNumeric<T extends bigint | number>(
  filter: $NumericFilter<T>,
  value: T,
) {
  if (
    filter.in !== undefined &&
    !filter.in.some((inValue) => inValue === value)
  ) {
    return false;
  }

  if (filter.maxExclusive !== undefined && value >= filter.maxExclusive) {
    return false;
  }

  if (filter.maxInclusive !== undefined && value > filter.maxInclusive) {
    return false;
  }

  if (filter.minExclusive !== undefined && value <= filter.minExclusive) {
    return false;
  }

  if (filter.minInclusive !== undefined && value < filter.minInclusive) {
    return false;
  }

  return true;
}

function $filterString(filter: $StringFilter, value: string) {
  if (
    filter.in !== undefined &&
    !filter.in.some((inValue) => inValue === value)
  ) {
    return false;
  }

  if (filter.maxLength !== undefined && value.length > filter.maxLength) {
    return false;
  }

  if (filter.minLength !== undefined && value.length < filter.minLength) {
    return false;
  }

  return true;
}

function $filterTerm(
  filter: $TermFilter,
  value: BlankNode | Literal | NamedNode,
): boolean {
  if (
    filter.datatypeIn !== undefined &&
    (value.termType !== "Literal" ||
      !filter.datatypeIn.some((inDatatype) =>
        inDatatype.equals(value.datatype),
      ))
  ) {
    return false;
  }

  if (
    filter.in !== undefined &&
    !filter.in.some((inTerm) => inTerm.equals(value))
  ) {
    return false;
  }

  if (
    filter.languageIn !== undefined &&
    (value.termType !== "Literal" ||
      !filter.languageIn.some((inLanguage) => inLanguage === value.language))
  ) {
    return false;
  }

  if (
    filter.typeIn !== undefined &&
    !filter.typeIn.some((inType) => inType === value.termType)
  ) {
    return false;
  }

  return true;
}

type $FocusSparqlConstructTriplesFunction<FilterT> = (parameters: {
  filter: FilterT | undefined;
  focusIdentifier: NamedNode | Variable;
  ignoreRdfType: boolean;
  variablePrefix: string;
}) => readonly sparqljs.Triple[];

type $FocusSparqlWherePatternsFunction<FilterT> = (parameters: {
  filter: FilterT | undefined;
  focusIdentifier: NamedNode | Variable;
  ignoreRdfType: boolean;
  preferredLanguages: readonly string[] | undefined;
  variablePrefix: string;
}) => readonly $SparqlPattern[];

function $fromRdfLanguageIn(
  values: Resource.Values,
  languageIn: readonly string[],
): Either<Error, Resource.Values> {
  return values.chainMap((value) =>
    value.toLiteral().chain((literal) =>
      languageIn.includes(literal.language)
        ? Right(value)
        : Left(
            new Resource.MistypedTermValueError({
              actualValue: literal,
              expectedValueType: "Literal",
              focusResource: value.focusResource,
              propertyPath: value.propertyPath,
            }),
          ),
    ),
  );
}

function $fromRdfPreferredLanguages(
  values: Resource.Values,
  preferredLanguages?: readonly string[],
): Either<Error, Resource.Values> {
  if (!preferredLanguages || preferredLanguages.length === 0) {
    return Right(values);
  }

  // Return all literals for the first preferredLanguage, then all literals for the second preferredLanguage, etc.
  // Within a preferredLanguage the literals may be in any order.
  const filteredValues: Resource.Value[] = [];
  for (const preferredLanguage of preferredLanguages) {
    for (const value of values) {
      value.toLiteral().ifRight((literal) => {
        if (literal.language === preferredLanguage) {
          filteredValues.push(value);
        }
      });
    }
  }

  return Right(
    Resource.Values.fromArray({
      focusResource: values.focusResource,
      propertyPath: values.propertyPath,
      values: filteredValues,
    }),
  );
}

export type $FromRdfResourceFunction<T> = (
  resource: Resource,
  options?: {
    context?: unknown;
    graph?: Exclude<Quad_Graph, Variable>;
    ignoreRdfType?: boolean;
    objectSet?: $ObjectSet;
    preferredLanguages?: readonly string[];
  },
) => Either<Error, T>;

export type $FromRdfResourceValuesFunction<T> = (
  resourceValues: Either<Error, Resource.Values>,
  options: {
    context?: unknown;
    graph?: Exclude<Quad_Graph, Variable>;
    ignoreRdfType?: boolean;
    objectSet?: $ObjectSet;
    preferredLanguages?: readonly string[];
    propertyPath: $PropertyPath;
    resource: Resource;
  },
) => Either<Error, Resource.Values<T>>;

type $Hasher = {
  update: (message: string | number[] | ArrayBuffer | Uint8Array) => void;
};

interface $IdentifierFilter {
  readonly in?: readonly (BlankNode | NamedNode)[];
  readonly type?: "BlankNode" | "NamedNode";
}

interface $IdentifierSchema {
  readonly kind: "Identifier";
}

class $IdentifierSet {
  private readonly blankNodeValues = new Set<string>();
  private readonly namedNodeValues = new Set<string>();

  add(identifier: BlankNode | NamedNode): this {
    switch (identifier.termType) {
      case "BlankNode":
        this.blankNodeValues.add(identifier.value);
        return this;
      case "NamedNode":
        this.namedNodeValues.add(identifier.value);
        return this;
    }
  }

  has(identifier: BlankNode | NamedNode): boolean {
    switch (identifier.termType) {
      case "BlankNode":
        return this.blankNodeValues.has(identifier.value);
      case "NamedNode":
        return this.namedNodeValues.has(identifier.value);
    }
  }
}

const $identifierSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $IdentifierFilter,
  $IdentifierSchema
> = ({ filter, propertyPatterns, valueVariable }) => {
  const patterns: $SparqlPattern[] = propertyPatterns.concat();

  if (filter) {
    if (filter.in !== undefined) {
      const valueIn = filter.in.filter(
        (identifier) => identifier.termType === "NamedNode",
      );
      if (valueIn.length > 0) {
        patterns.push(
          $sparqlValueInPattern({ lift: true, valueVariable, valueIn }),
        );
      }
    }

    if (filter.type !== undefined) {
      patterns.push({
        expression: {
          type: "operation",
          operator: filter.type === "BlankNode" ? "isBlank" : "isIRI",
          args: [valueVariable],
        },
        lift: true,
        type: "filter",
      });
    }
  }

  return patterns;
};

interface $IriFilter {
  readonly in?: readonly NamedNode[];
}

interface $IriSchema {
  readonly in?: readonly NamedNode[];
  readonly kind: "Iri";
}

const $iriSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $IriFilter,
  $IriSchema
> = ({ filter, valueVariable, ...otherParameters }) => {
  const filterPatterns: $SparqlFilterPattern[] = [];

  if (filter?.in !== undefined && filter.in.length > 0) {
    filterPatterns.push(
      $sparqlValueInPattern({ lift: true, valueVariable, valueIn: filter.in }),
    );
  }

  return $termSchemaSparqlPatterns({
    ...otherParameters,
    filterPatterns,
    valueVariable,
  });
};

function $isReadonlyBigIntArray(x: unknown): x is readonly bigint[] {
  return Array.isArray(x) && x.every((z) => typeof z === "bigint");
}

function $isReadonlyBooleanArray(x: unknown): x is readonly boolean[] {
  return Array.isArray(x) && x.every((z) => typeof z === "boolean");
}

function $isReadonlyNumberArray(x: unknown): x is readonly number[] {
  return Array.isArray(x) && x.every((z) => typeof z === "number");
}

function $isReadonlyObjectArray(x: unknown): x is readonly object[] {
  return Array.isArray(x) && x.every((z) => typeof z === "object");
}

function $isReadonlyStringArray(x: unknown): x is readonly string[] {
  return Array.isArray(x) && x.every((z) => typeof z === "string");
}

/**
 * Type of lazy properties that return a single required object. This is a class instead of an interface so it can be instanceof'd elsewhere.
 */
export class $LazyObject<
  ObjectIdentifierT extends BlankNode | NamedNode,
  PartialObjectT extends { $identifier: () => ObjectIdentifierT },
  ResolvedObjectT extends { $identifier: () => ObjectIdentifierT },
> {
  readonly partial: PartialObjectT;
  private readonly resolver: (
    identifier: ObjectIdentifierT,
    options?: { preferredLanguages?: readonly string[] },
  ) => Promise<Either<Error, ResolvedObjectT>>;

  constructor({
    partial,
    resolver,
  }: {
    partial: PartialObjectT;
    resolver: (
      identifier: ObjectIdentifierT,
      options?: { preferredLanguages?: readonly string[] },
    ) => Promise<Either<Error, ResolvedObjectT>>;
  }) {
    this.partial = partial;
    this.resolver = resolver;
  }

  resolve(options?: {
    preferredLanguages?: readonly string[];
  }): Promise<Either<Error, ResolvedObjectT>> {
    return this.resolver(this.partial.$identifier(), options);
  }
}

/**
 * Type of lazy properties that return a single optional object. This is a class instead of an interface so it can be instanceof'd elsewhere.
 */
export class $LazyObjectOption<
  ObjectIdentifierT extends BlankNode | NamedNode,
  PartialObjectT extends { $identifier: () => ObjectIdentifierT },
  ResolvedObjectT extends { $identifier: () => ObjectIdentifierT },
> {
  readonly partial: Maybe<PartialObjectT>;
  private readonly resolver: (
    identifier: ObjectIdentifierT,
    options?: { preferredLanguages?: readonly string[] },
  ) => Promise<Either<Error, ResolvedObjectT>>;

  constructor({
    partial,
    resolver,
  }: {
    partial: Maybe<PartialObjectT>;
    resolver: (
      identifier: ObjectIdentifierT,
      options?: { preferredLanguages?: readonly string[] },
    ) => Promise<Either<Error, ResolvedObjectT>>;
  }) {
    this.partial = partial;
    this.resolver = resolver;
  }

  async resolve(options?: {
    preferredLanguages?: readonly string[];
  }): Promise<Either<Error, Maybe<ResolvedObjectT>>> {
    if (this.partial.isNothing()) {
      return Right(Maybe.empty());
    }
    return (
      await this.resolver(this.partial.unsafeCoerce().$identifier(), options)
    ).map(Maybe.of);
  }
}

/**
 * Type of lazy properties that return a set of objects. This is a class instead of an interface so it can be instanceof'd elsewhere.
 */
export class $LazyObjectSet<
  ObjectIdentifierT extends BlankNode | NamedNode,
  PartialObjectT extends { $identifier: () => ObjectIdentifierT },
  ResolvedObjectT extends { $identifier: () => ObjectIdentifierT },
> {
  readonly partials: readonly PartialObjectT[];
  private readonly resolver: (
    identifiers: readonly ObjectIdentifierT[],
    options?: { preferredLanguages?: readonly string[] },
  ) => Promise<Either<Error, readonly ResolvedObjectT[]>>;

  constructor({
    partials,
    resolver,
  }: {
    partials: readonly PartialObjectT[];
    resolver: (
      identifiers: readonly ObjectIdentifierT[],
      options?: { preferredLanguages?: readonly string[] },
    ) => Promise<Either<Error, readonly ResolvedObjectT[]>>;
  }) {
    this.partials = partials;
    this.resolver = resolver;
  }

  get length(): number {
    return this.partials.length;
  }

  async resolve(options?: {
    limit?: number;
    offset?: number;
    preferredLanguages?: readonly string[];
  }): Promise<Either<Error, readonly ResolvedObjectT[]>> {
    if (this.partials.length === 0) {
      return Right([]);
    }

    const limit = options?.limit ?? Number.MAX_SAFE_INTEGER;
    if (limit <= 0) {
      return Right([]);
    }

    let offset = options?.offset ?? 0;
    if (offset < 0) {
      offset = 0;
    }

    return await this.resolver(
      this.partials
        .slice(offset, offset + limit)
        .map((partial) => partial.$identifier()),
      {
        preferredLanguages: options?.preferredLanguages,
      },
    );
  }
}

function $liftSparqlPatterns(
  patterns: Iterable<$SparqlPattern>,
): [readonly $SparqlPattern[], readonly $SparqlFilterPattern[]] {
  const liftedPatterns: $SparqlFilterPattern[] = [];
  const unliftedPatterns: $SparqlPattern[] = [];
  for (const pattern of patterns) {
    if (pattern.type === "filter" && pattern.lift) {
      liftedPatterns.push(pattern);
    } else {
      unliftedPatterns.push(pattern);
    }
  }
  return [unliftedPatterns, liftedPatterns];
}

function $listSparqlConstructTriples<ItemFilterT, ItemSchemaT>(
  itemSparqlConstructTriplesFunction: $ValueSparqlConstructTriplesFunction<
    ItemFilterT,
    ItemSchemaT
  >,
): $ValueSparqlConstructTriplesFunction<
  $CollectionFilter<ItemFilterT>,
  $CollectionSchema<ItemSchemaT>
> {
  return ({
    filter,
    schema,
    valueVariable: listVariable,
    variablePrefix: variablePrefixPrefix,
  }) => {
    let triples: sparqljs.Triple[] = [];
    const variable = (suffix: string) =>
      dataFactory.variable!(`${variablePrefixPrefix}${suffix}`);
    const variablePrefix = (suffix: string) =>
      `${variablePrefixPrefix}${suffix}`;

    {
      // ?list rdf:first ?item0
      const item0Variable = variable("Item0");
      triples.push({
        subject: listVariable,
        predicate: $RdfVocabularies.rdf.first,
        object: item0Variable,
      });
      triples = triples.concat(
        itemSparqlConstructTriplesFunction({
          filter,
          ignoreRdfType: false,
          schema: schema.item(),
          valueVariable: item0Variable,
          variablePrefix: variablePrefix("Item0"),
        }),
      );
    }
    // ?list rdf:rest ?rest0
    triples.push({
      subject: listVariable,
      predicate: $RdfVocabularies.rdf.rest,
      object: variable("Rest0"),
    });

    // Don't do ?list rdf:rest+ ?restN in CONSTRUCT
    const restNVariable = variable("RestN");

    {
      // ?rest rdf:first ?itemN
      const itemNVariable = variable("ItemN");
      triples.push({
        subject: restNVariable,
        predicate: $RdfVocabularies.rdf.first,
        object: itemNVariable,
      });
      triples = triples.concat(
        itemSparqlConstructTriplesFunction({
          filter,
          ignoreRdfType: false,
          schema: schema.item(),
          valueVariable: itemNVariable,
          variablePrefix: variablePrefix("ItemN"),
        }),
      );
    }

    // ?restN rdf:rest ?restNBasic to get the rdf:rest statement in the CONSTRUCT
    triples.push({
      subject: restNVariable,
      predicate: $RdfVocabularies.rdf.rest,
      object: variable("RestNBasic"),
    });

    return triples;
  };
}

function $listSparqlWherePatterns<ItemFilterT, ItemSchemaT>(
  itemSparqlWherePatternsFunction: $ValueSparqlWherePatternsFunction<
    ItemFilterT,
    ItemSchemaT
  >,
): $ValueSparqlWherePatternsFunction<
  $CollectionFilter<ItemFilterT>,
  $CollectionSchema<ItemSchemaT>
> {
  return (parameters) => {
    // Need to handle two cases:
    // (1) (?s, ?p, ?list) where ?list binds to rdf:nil
    // (2) (?s, ?p, ?list) (?list, rdf:first, "element") (?list, rdf:rest, rdf:nil) etc. where list binds to the head of a list
    // Case (2) is case (1) with OPTIONAL graph patterns to handle actual list elements.

    const listVariable = parameters.valueVariable;
    const patterns: $SparqlPattern[] = [];
    const variable = (suffix: string) =>
      dataFactory.variable!(`${parameters.variablePrefix}${suffix}`);
    const variablePrefix = (suffix: string) =>
      `${parameters.variablePrefix}${suffix}`;

    {
      // ?list rdf:first ?item0
      const item0Variable = variable("Item0");
      patterns.push(
        {
          triples: [
            {
              subject: listVariable,
              predicate: $RdfVocabularies.rdf.first,
              object: item0Variable,
            },
          ],
          type: "bgp",
        },
        ...itemSparqlWherePatternsFunction({
          filter: parameters.filter,
          ignoreRdfType: parameters.ignoreRdfType,
          preferredLanguages: parameters.preferredLanguages,
          propertyPatterns: [],
          schema: parameters.schema.item(),
          valueVariable: item0Variable,
          variablePrefix: variablePrefix("Item0"),
        }),
      );
    }

    {
      // ?list rdf:rest ?rest0
      const rest0Variable = variable("Rest0");
      patterns.push({
        triples: [
          {
            subject: listVariable,
            predicate: $RdfVocabularies.rdf.rest,
            object: rest0Variable,
          },
        ],
        type: "bgp",
      });
    }

    const optionalPatterns: $SparqlPattern[] = [];

    const restNVariable = variable("RestN");
    // ?list rdf:rest+ ?restN
    optionalPatterns.push({
      type: "bgp",
      triples: [
        {
          subject: listVariable,
          predicate: {
            type: "path",
            pathType: "*",
            items: [$RdfVocabularies.rdf.rest],
          },
          object: restNVariable,
        },
      ],
    });

    {
      // ?rest rdf:first ?itemN
      const itemNVariable = variable("ItemN");
      optionalPatterns.push(
        {
          triples: [
            {
              subject: restNVariable,
              predicate: $RdfVocabularies.rdf.first,
              object: itemNVariable,
            },
          ],
          type: "bgp",
        },
        ...itemSparqlWherePatternsFunction({
          filter: parameters.filter,
          ignoreRdfType: parameters.ignoreRdfType,
          preferredLanguages: parameters.preferredLanguages,
          propertyPatterns: [],
          schema: parameters.schema.item(),
          valueVariable: itemNVariable,
          variablePrefix: variablePrefix("ItemN"),
        }),
      );
    }

    // ?restN rdf:rest ?restNBasic to get the rdf:rest statement in the CONSTRUCT
    optionalPatterns.push({
      triples: [
        {
          subject: restNVariable,
          predicate: $RdfVocabularies.rdf.rest,
          object: variable("RestNBasic"),
        },
      ],
      type: "bgp",
    });

    patterns.push({ type: "optional", patterns: optionalPatterns });

    // Having an optional around everything handles the rdf:nil case
    return [...parameters.propertyPatterns, { patterns, type: "optional" }];
  };
}

const $literalFactory = new LiteralFactory({ dataFactory: dataFactory });

interface $LiteralFilter extends Omit<$TermFilter, "in" | "type"> {
  readonly in?: readonly Literal[];
}

interface $LiteralSchema {
  readonly in?: readonly Literal[];
  readonly kind: "Literal";
  readonly languageIn?: readonly string[];
}

function $literalSchemaSparqlPatterns({
  filterPatterns,
  preferredLanguages,
  propertyPatterns,
  schema,
  valueVariable,
}: {
  filterPatterns: readonly $SparqlFilterPattern[];
  preferredLanguages?: readonly string[];
  propertyPatterns: readonly $SparqlPattern[];
  schema: Readonly<{
    languageIn?: readonly string[];
    in?: readonly (
      | bigint
      | boolean
      | Date
      | string
      | number
      | Literal
      | NamedNode
    )[];
  }>;
  valueVariable: Variable;
}): readonly $SparqlPattern[] {
  const patterns: $SparqlPattern[] = propertyPatterns.concat();

  if (schema.in && schema.in.length > 0) {
    patterns.push($sparqlValueInPattern({ valueVariable, valueIn: schema.in }));
  }

  const languageIn = $arrayIntersection(
    schema.languageIn ?? [],
    preferredLanguages ?? [],
  );
  if (languageIn.length > 0) {
    patterns.push({
      expression: {
        args: [
          { args: [valueVariable], operator: "lang", type: "operation" },
          languageIn.map((_) => dataFactory.literal(_)),
        ],
        operator: "in",
        type: "operation",
      },
      type: "filter",
    });
  }

  return patterns.concat(filterPatterns);
}

const $literalSparqlWherePatterns: $ValueSparqlWherePatternsFunction<
  $LiteralFilter,
  $LiteralSchema
> = (parameters) =>
  $literalSchemaSparqlPatterns({
    filterPatterns: $termFilterSparqlPatterns(parameters),
    ...parameters,
  });

function $maybeEquals<T>(
  leftMaybe: Maybe<T>,
  rightMaybe: Maybe<T>,
  valueEquals: (left: T, right: T) => boolean | $EqualsResult,
): $EqualsResult {
  if (leftMaybe.isJust()) {
    if (rightMaybe.isJust()) {
      return $EqualsResult.fromBooleanEqualsResult(
        leftMaybe,
        rightMaybe,
        valueEquals(leftMaybe.unsafeCoerce(), rightMaybe.unsafeCoerce()),
      );
    }
    return Left({ left: leftMaybe.unsafeCoerce(), type: "right-null" });
  }

  if (rightMaybe.isJust()) {
    return Left({ right: rightMaybe.unsafeCoerce(), type: "left-null" });
  }

  return $EqualsResult.Equal;
}

type $MaybeFilter<ItemFilterT> = ItemFilterT | null;

interface $MaybeSchema<ItemSchemaT> {
  readonly item: () => ItemSchemaT;
  readonly kind: "Maybe";
}

function $maybeSparqlConstructTriples<ItemFilterT, ItemSchemaT>(
  itemSparqlConstructTriplesFunction: $ValueSparqlConstructTriplesFunction<
    ItemFilterT,
    ItemSchemaT
  >,
): $ValueSparqlConstructTriplesFunction<
  $MaybeFilter<ItemFilterT>,
  $MaybeSchema<ItemSchemaT>
> {
  return ({ filter, schema, ...otherParameters }) =>
    itemSparqlConstructTriplesFunction({
      ...otherParameters,
      filter: filter ?? undefined,
      schema: schema.item(),
    });
}

function $maybeSparqlWherePatterns<ItemFilterT, ItemSchemaT>(
  itemSparqlWherePatternsFunction: $ValueSparqlWherePatternsFunction<
    ItemFilterT,
    ItemSchemaT
  >,
): $ValueSparqlWherePatternsFunction<
  $MaybeFilter<ItemFilterT>,
  $MaybeSchema<ItemSchemaT>
> {
  return ({ filter, schema, ...otherParameters }) => {
    if (filter === undefined) {
      // Treat the item's patterns as optional
      const [itemSparqlWherePatterns, liftSparqlPatterns] = $liftSparqlPatterns(
        itemSparqlWherePatternsFunction({
          ...otherParameters,
          filter,
          schema: schema.item(),
        }),
      );
      return [
        { patterns: itemSparqlWherePatterns.concat(), type: "optional" },
        ...liftSparqlPatterns,
      ];
    }

    if (filter === null) {
      // Use FILTER NOT EXISTS around the item's patterns
      const [itemSparqlWherePatterns, liftSparqlPatterns] = $liftSparqlPatterns(
        itemSparqlWherePatternsFunction({
          ...otherParameters,
          filter: undefined,
          schema: schema.item(),
        }),
      );
      return [
        {
          expression: {
            args: itemSparqlWherePatterns.concat(),
            operator: "notexists",
            type: "operation",
          },
          lift: true,
          type: "filter",
        },
        ...liftSparqlPatterns,
      ];
    }

    // Treat the item as required.
    return itemSparqlWherePatternsFunction({
      ...otherParameters,
      filter,
      schema: schema.item(),
    });
  };
}

function $normalizeSparqlWherePatterns(
  patterns: readonly $SparqlPattern[],
): readonly $SparqlPattern[] {
  function normalizePatternsRecursive(
    patternsRecursive: readonly $SparqlPattern[],
  ): readonly $SparqlPattern[] {
    if (patternsRecursive.length === 0) {
      return patternsRecursive;
    }

    const compactedPatterns: $SparqlPattern[] = [];
    for (const pattern of $deduplicateSparqlPatterns(patternsRecursive)) {
      switch (pattern.type) {
        case "bgp": {
          if (pattern.triples.length === 0) {
            continue;
          }
          const lastPattern = compactedPatterns.at(-1);
          if (lastPattern && lastPattern.type === "bgp") {
            // Coalesce adjacent BGP patterns without mutating lastPattern
            compactedPatterns[compactedPatterns.length - 1] = {
              triples: lastPattern.triples.concat(pattern.triples),
              type: "bgp",
            };
          } else {
            compactedPatterns.push(pattern);
          }
          break;
        }
        case "bind":
        case "filter":
        case "query":
        case "values":
          compactedPatterns.push(pattern);
          break;
        case "group":
          // Flatten groups outside unions
          compactedPatterns.push(
            ...normalizePatternsRecursive(pattern.patterns),
          );
          break;
        case "graph":
        case "minus":
        case "optional":
        case "service": {
          const patterns_ = normalizePatternsRecursive(pattern.patterns);
          if (patterns_.length > 0) {
            compactedPatterns.push({
              ...pattern,
              patterns: patterns_.concat(),
            });
          }
          break;
        }
        case "union": {
          const unionPatterns = $deduplicateSparqlPatterns(
            pattern.patterns.flatMap((pattern) => {
              switch (pattern.type) {
                case "group":
                // Don't flatten the groups in a union
                case "graph":
                case "minus":
                case "optional":
                case "service": {
                  const patterns_ = normalizePatternsRecursive(
                    pattern.patterns,
                  );
                  if (patterns_.length > 0) {
                    return [{ ...pattern, patterns: patterns_.concat() }];
                  }
                  return [] as $SparqlPattern[];
                }
                default:
                  return [pattern];
              }
            }),
          );

          switch (unionPatterns.length) {
            case 0:
              break;
            case 1:
              compactedPatterns.push(
                ...normalizePatternsRecursive([unionPatterns[0]]),
              );
              break;
            default:
              compactedPatterns.push({
                ...pattern,
                patterns: unionPatterns.concat(),
              });
              break;
          }
          break;
        }
        default:
          pattern satisfies never;
      }
    }

    return $sortSparqlPatterns($deduplicateSparqlPatterns(compactedPatterns));
  }

  const normalizedPatterns = normalizePatternsRecursive(patterns);
  if (!normalizedPatterns.some($SparqlPattern.isSolutionGenerating)) {
    throw new Error(
      "SPARQL WHERE patterns must have at least one solution-generating pattern",
    );
  }

  return normalizedPatterns;
}

interface $NumericFilter<T> {
  readonly in?: readonly T[];
  readonly maxExclusive?: T;
  readonly maxInclusive?: T;
  readonly minExclusive?: T;
  readonly minInclusive?: T;
}

interface $NumericSchema<T> {
  readonly in?: readonly T[];
  readonly kind: "BigDecimal" | "BigInt" | "Float" | "Int";
}

function $numericSparqlWherePatterns<T extends bigint | number>({
  filter,
  valueVariable,
  ...otherParameters
}: Parameters<
  $ValueSparqlWherePatternsFunction<$NumericFilter<T>, $NumericSchema<T>>
>[0]): ReturnType<
  $ValueSparqlWherePatternsFunction<$NumericFilter<T>, $NumericSchema<T>>
> {
  const filterPatterns: $SparqlFilterPattern[] = [];

  if (filter) {
    if (filter.in !== undefined && filter.in.length > 0) {
      filterPatterns.push(
        $sparqlValueInPattern({
          lift: true,
          valueVariable,
          valueIn: filter.in,
        }),
      );
    }

    if (filter.maxExclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "<",
          args: [valueVariable, $literalFactory.primitive(filter.maxExclusive)],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.maxInclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: "<=",
          args: [valueVariable, $literalFactory.primitive(filter.maxInclusive)],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.minExclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: ">",
          args: [valueVariable, $literalFactory.primitive(filter.minExclusive)],
        },
        lift: true,
        type: "filter",
      });
    }

    if (filter.minInclusive !== undefined) {
      filterPatterns.push({
        expression: {
          type: "operation",
          operator: ">=",
          args: [valueVariable, $literalFactory.primitive(filter.minInclusive)],
        },
        lift: true,
        type: "filter",
      });
    }
  }

  return $termSchemaSparqlPatterns({
    ...otherParameters,
    filterPatterns,
    valueVariable,
  });
}

export function $parseBlankNode(identifier: string): Either<Error, BlankNode> {
  return $parseIdentifier(identifier).chain((identifier) =>
    identifier.termType === "BlankNode"
      ? Right(identifier)
      : Left(new Error("expected identifier to be BlankNode")),
  ) as Either<Error, BlankNode>;
}

const $parseIdentifier = NTriplesIdentifier.parser(dataFactory);

export function $parseIri(identifier: string): Either<Error, NamedNode> {
  return $parseIdentifier(identifier).chain((identifier) =>
    identifier.termType === "NamedNode"
      ? Right(identifier)
      : Left(new Error("expected identifier to be NamedNode")),
  ) as Either<Error, NamedNode>;
}

export type $PropertyPath = RdfxResourcePropertyPath;

export namespace $PropertyPath {
  export type Filter = object;

  export function filter(_filter: Filter, _value: $PropertyPath): boolean {
    return true;
  }

  export const fromRdfResource: $FromRdfResourceFunction<$PropertyPath> =
    RdfxResourcePropertyPath.fromResource;

  export const fromRdfResourceValues: $FromRdfResourceValuesFunction<
    $PropertyPath
  > = (values, options) =>
    values.chain((values) =>
      values.chainMap((value) =>
        value
          .toResource()
          .chain((resource) => fromRdfResource(resource, options)),
      ),
    );

  export const schema: Readonly<object> = {};

  export const toRdfResource: $ToRdfResourceFunction<$PropertyPath> =
    RdfxResourcePropertyPath.toResource;

  export const $toString = RdfxResourcePropertyPath.toString;
}

