  export const fromRdfType: NamedNode<string> = dataFactory.namedNode(
    "http://example.com/NumericProperties",
  );

  export function isNumericProperties(
    object: $Object,
  ): object is NumericProperties {
    switch (object.$type) {
      case "NumericProperties":
        return true;
      default:
        return false;
    }
  }

